let html = '<h2 style="color: #2c3e50;">🤖 Noticias de Inteligencia Artificial (últimas 24 hs)</h2><hr><br>';
const items = $input.all();

if (items.length === 0) {
  html += '<p>No se encontraron noticias recientes.</p>';
} else {
  let limite = items.length > 15 ? 15 : items.length; // Limitamos a 15 noticias para no hacer muy extenso el email
  for (let i = 0; i < limite; i++) {
    const item = items[i].json;
    const title = item.title;
    const link = item.link;
    let description = item.contentSnippet || item.content || item.description || 'Sin descripción detallada.';

    // Limpiar etiquetas HTML extrañas que a veces trae Google News en la descripción
    description = description.replace(/<[^>]*>?/gm, '');

    html += `
      <div style="margin-bottom: 20px;">
        <h3 style="margin-bottom: 5px; color: #2980b9;"><a href="${link}" target="_blank" style="text-decoration: none; color: #2980b9;">${title}</a></h3>
        <p style="margin-top: 0; color: #555;">${description}</p>
        <a href="${link}" style="color: #e67e22; font-weight: bold; text-decoration: none;">Leer noticia completa →</a>
      </div>
    `;
  }
}

return [{ json: { htmlEmail: html } }];
